/**
 * Article Validation Schema Tests
 * Tests the article data structures and validation rules
 */

import { 
  ArticleSectionSchema, 
  ContentQualitySchema, 
  ArticleSchema,
  AIGenerationMetadataSchema,
  generateSlug 
} from '../article';

describe('Article Validation Schemas', () => {
  describe('ArticleSectionSchema', () => {
    it('should validate a complete article section', () => {
      const section = {
        id: 'section_1',
        type: 'intro',
        content: 'This is the introduction section of the article.',
        sourceTweets: ['tweet_123', 'tweet_456'],
        order: 0,
        wordCount: 45,
      };

      expect(section).toBeValidZodSchema(ArticleSectionSchema);
    });

    it('should validate section with minimum required fields', () => {
      const section = {
        id: 'section_2',
        type: 'content',
        content: 'Main content here.',
        sourceTweets: [],
        order: 1,
        wordCount: 12,
      };

      expect(section).toBeValidZodSchema(ArticleSectionSchema);
    });

    it('should reject section with invalid type', () => {
      const section = {
        id: 'section_1',
        type: 'invalid_type',
        content: 'Content here',
        sourceTweets: [],
        order: 0,
        wordCount: 10,
      };

      expect(section).toHaveZodError(ArticleSectionSchema, 'Invalid enum value');
    });

    it('should reject section with negative order', () => {
      const section = {
        id: 'section_1',
        type: 'intro',
        content: 'Content here',
        sourceTweets: [],
        order: -1,
        wordCount: 10,
      };

      expect(section).toHaveZodError(ArticleSectionSchema, 'Number must be greater than or equal to 0');
    });

    it('should reject section with empty content', () => {
      const section = {
        id: 'section_1',
        type: 'intro',
        content: '',
        sourceTweets: [],
        order: 0,
        wordCount: 0,
      };

      expect(section).toHaveZodError(ArticleSectionSchema, 'String must contain at least 1 character');
    });
  });

  describe('ContentQualitySchema', () => {
    it('should validate complete quality metrics', () => {
      const quality = {
        grammarScore: 95,
        readabilityScore: 88,
        brandVoiceScore: 92,
        factualAccuracy: 97,
        engagementPotential: 85,
        overallScore: 91,
        flags: ['minor_grammar'],
        humanReviewRequired: false,
      };

      expect(quality).toBeValidZodSchema(ContentQualitySchema);
    });

    it('should validate minimal quality object', () => {
      const quality = {
        grammarScore: 70,
        readabilityScore: 60,
        brandVoiceScore: 65,
        factualAccuracy: 80,
        engagementPotential: 55,
        overallScore: 66,
        flags: [],
        humanReviewRequired: true,
      };

      expect(quality).toBeValidZodSchema(ContentQualitySchema);
    });

    it('should reject scores outside valid range', () => {
      const quality = {
        grammarScore: 105, // Invalid: over 100
        readabilityScore: 88,
        brandVoiceScore: 92,
        factualAccuracy: 97,
        engagementPotential: 85,
        overallScore: 91,
        flags: [],
        humanReviewRequired: false,
      };

      expect(quality).toHaveZodError(ContentQualitySchema, 'Number must be less than or equal to 100');
    });

    it('should reject negative scores', () => {
      const quality = {
        grammarScore: -5,
        readabilityScore: 88,
        brandVoiceScore: 92,
        factualAccuracy: 97,
        engagementPotential: 85,
        overallScore: 91,
        flags: [],
        humanReviewRequired: false,
      };

      expect(quality).toHaveZodError(ContentQualitySchema, 'Number must be greater than or equal to 0');
    });

    it('should validate with various flag types', () => {
      const quality = {
        grammarScore: 70,
        readabilityScore: 75,
        brandVoiceScore: 80,
        factualAccuracy: 85,
        engagementPotential: 70,
        overallScore: 76,
        flags: ['grammar_issues', 'readability_concerns', 'brand_voice_deviation'],
        humanReviewRequired: true,
      };

      expect(quality).toBeValidZodSchema(ContentQualitySchema);
    });
  });

  describe('AIGenerationMetadataSchema', () => {
    it('should validate complete AI metadata', () => {
      const metadata = {
        model: 'gpt-4',
        promptVersion: '2.1',
        temperature: 0.7,
        maxTokens: 2000,
        generatedAt: new Date('2024-01-15T10:00:00Z'),
        processingTimeMs: 3500,
        tokenUsage: {
          prompt: 150,
          completion: 800,
          total: 950,
        },
        qualityChecks: {
          grammarCheck: true,
          factCheck: true,
          brandVoiceCheck: true,
        },
      };

      expect(metadata).toBeValidZodSchema(AIGenerationMetadataSchema);
    });

    it('should validate minimal AI metadata', () => {
      const metadata = {
        model: 'claude-3',
        promptVersion: '1.0',
        temperature: 0.5,
        maxTokens: 1500,
        generatedAt: new Date(),
        processingTimeMs: 2000,
        tokenUsage: {
          prompt: 100,
          completion: 600,
          total: 700,
        },
        qualityChecks: {
          grammarCheck: false,
          factCheck: false,
          brandVoiceCheck: false,
        },
      };

      expect(metadata).toBeValidZodSchema(AIGenerationMetadataSchema);
    });

    it('should reject invalid temperature values', () => {
      const metadata = {
        model: 'gpt-4',
        promptVersion: '2.1',
        temperature: 1.5, // Invalid: over 1.0
        maxTokens: 2000,
        generatedAt: new Date(),
        processingTimeMs: 3500,
        tokenUsage: {
          prompt: 150,
          completion: 800,
          total: 950,
        },
        qualityChecks: {
          grammarCheck: true,
          factCheck: true,
          brandVoiceCheck: true,
        },
      };

      expect(metadata).toHaveZodError(AIGenerationMetadataSchema, 'Number must be less than or equal to 1');
    });

    it('should reject inconsistent token usage totals', () => {
      const metadata = {
        model: 'gpt-4',
        promptVersion: '2.1',
        temperature: 0.7,
        maxTokens: 2000,
        generatedAt: new Date(),
        processingTimeMs: 3500,
        tokenUsage: {
          prompt: 150,
          completion: 800,
          total: 800, // Should be 950
        },
        qualityChecks: {
          grammarCheck: true,
          factCheck: true,
          brandVoiceCheck: true,
        },
      };

      expect(metadata).toHaveZodError(AIGenerationMetadataSchema, 'Token usage total must equal prompt + completion tokens');
    });
  });

  describe('ArticleSchema', () => {
    it('should validate a complete article', () => {
      const article = {
        id: 'article_123',
        title: 'Arsenal Complete Declan Rice Signing',
        briefingType: 'morning',
        status: 'published',
        sections: [
          {
            id: 'section_1',
            type: 'intro',
            content: 'Arsenal have completed the signing of Declan Rice.',
            sourceTweets: ['tweet_123'],
            order: 0,
            wordCount: 45,
          }
        ],
        summary: 'Arsenal complete major signing of England midfielder Declan Rice.',
        publishedAt: new Date('2024-01-15T10:00:00Z'),
        lastModified: new Date('2024-01-15T10:30:00Z'),
        quality: {
          grammarScore: 95,
          readabilityScore: 88,
          brandVoiceScore: 92,
          factualAccuracy: 97,
          engagementPotential: 85,
          overallScore: 91,
          flags: [],
          humanReviewRequired: false,
        },
        sourceTweets: ['tweet_123'],
        totalSourceTweets: 1,
        slug: 'arsenal-complete-declan-rice-signing',
        metaDescription: 'Arsenal complete major signing of England midfielder Declan Rice from West Ham United.',
        tags: ['Arsenal', 'Transfer', 'Declan Rice'],
        estimatedReadTime: 2,
        wordCount: 250,
        sentToSubscribers: true,
      };

      expect(article).toBeValidZodSchema(ArticleSchema);
    });

    it('should validate draft article with minimal fields', () => {
      const article = {
        id: 'draft_456',
        title: 'Chelsea Monitor Bellingham',
        briefingType: 'evening',
        status: 'draft',
        sections: [
          {
            id: 'section_1',
            type: 'content',
            content: 'Chelsea are monitoring Jude Bellingham situation.',
            sourceTweets: [],
            order: 0,
            wordCount: 30,
          }
        ],
        summary: 'Chelsea monitoring Bellingham.',
        lastModified: new Date(),
        quality: {
          grammarScore: 70,
          readabilityScore: 65,
          brandVoiceScore: 60,
          factualAccuracy: 75,
          engagementPotential: 55,
          overallScore: 65,
          flags: ['needs_review'],
          humanReviewRequired: true,
        },
        sourceTweets: [],
        totalSourceTweets: 0,
        slug: 'chelsea-monitor-bellingham',
        metaDescription: 'Chelsea are keeping tabs on Jude Bellingham transfer situation.',
        tags: ['Chelsea'],
        estimatedReadTime: 1,
        wordCount: 150,
        sentToSubscribers: false,
      };

      expect(article).toBeValidZodSchema(ArticleSchema);
    });

    it('should reject article with empty title', () => {
      const article = {
        id: 'article_123',
        title: '',
        briefingType: 'morning',
        status: 'published',
        sections: [],
        summary: 'Test summary',
        lastModified: new Date(),
        quality: {
          grammarScore: 95,
          readabilityScore: 88,
          brandVoiceScore: 92,
          factualAccuracy: 97,
          engagementPotential: 85,
          overallScore: 91,
          flags: [],
          humanReviewRequired: false,
        },
        sourceTweets: [],
        totalSourceTweets: 0,
        slug: 'test-slug',
        metaDescription: 'Test description',
        tags: [],
        estimatedReadTime: 1,
        wordCount: 50,
        sentToSubscribers: false,
      };

      expect(article).toHaveZodError(ArticleSchema, 'String must contain at least 1 character');
    });

    it('should reject article with invalid briefing type', () => {
      const article = {
        id: 'article_123',
        title: 'Test Article',
        briefingType: 'midnight', // Invalid
        status: 'published',
        sections: [],
        summary: 'Test summary',
        lastModified: new Date(),
        quality: {
          grammarScore: 95,
          readabilityScore: 88,
          brandVoiceScore: 92,
          factualAccuracy: 97,
          engagementPotential: 85,
          overallScore: 91,
          flags: [],
          humanReviewRequired: false,
        },
        sourceTweets: [],
        totalSourceTweets: 0,
        slug: 'test-slug',
        metaDescription: 'Test description',
        tags: [],
        estimatedReadTime: 1,
        wordCount: 50,
        sentToSubscribers: false,
      };

      expect(article).toHaveZodError(ArticleSchema, 'Invalid enum value');
    });
  });

  describe('generateSlug utility', () => {
    it('should generate valid slug from title', () => {
      const title = 'Arsenal Complete Declan Rice Signing for £105m';
      const slug = generateSlug(title);
      
      expect(slug).toBe('arsenal-complete-declan-rice-signing-for-105m');
    });

    it('should handle special characters', () => {
      const title = 'Manchester United\'s £100m+ Jude Bellingham Deal!';
      const slug = generateSlug(title);
      
      expect(slug).toBe('manchester-united-s-100m-jude-bellingham-deal');
    });

    it('should handle multiple spaces and trim', () => {
      const title = '  Chelsea    Sign    New    Striker  ';
      const slug = generateSlug(title);
      
      expect(slug).toBe('chelsea-sign-new-striker');
    });

    it('should handle empty title', () => {
      const title = '';
      const slug = generateSlug(title);
      
      expect(slug).toBe('');
    });

    it('should handle title with only special characters', () => {
      const title = '!@#$%^&*()';
      const slug = generateSlug(title);
      
      expect(slug).toBe('');
    });
  });
});